@using Microsoft.AspNetCore.Components.Web
<!DOCTYPE html>
<html lang="en">

<head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <base href="/" />
    <ResourcePreloader />
    <link rel="stylesheet" href="@Assets["lib/bootstrap/dist/css/bootstrap.min.css"]" />
    <link rel="stylesheet" href="@Assets["app.css"]" />
    <link rel="stylesheet" href="@Assets["BlazorApp.styles.css"]" />
    <ImportMap />
    <link rel="icon" type="image/png" href="favicon.png" />
    <HeadOutlet @rendermode="@pageRenderMode" />
</head>

<body>
    <Routes @rendermode="@pageRenderMode" />
    @if (pageRenderMode is not null)
    {
        <ReconnectModal />
    }
    <script src="@Assets["_framework/blazor.web.js"]"></script>
</body>

</html>

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private IComponentRenderMode? pageRenderMode;

    protected override void OnInitialized()
    {
        var endpoint = HttpContext?.GetEndpoint();
        if (endpoint?.Metadata.GetMetadata<ExcludeFromInteractiveRoutingAttribute>() is not null)
        {
            pageRenderMode = null;
        }
        else
        {
            pageRenderMode = RenderMode.InteractiveServer;
        }
    }
}

